import { useState, useRef } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { cn } from "../lib/utils";

export function Timeline({ items }) {
  const [active, setActive] = useState(0);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [isHovering, setIsHovering] = useState(false);
  const buttonRefs = useRef([]);

  const prev = () => setActive((i) => Math.max(0, i - 1));
  const next = () => setActive((i) => Math.min(items.length - 1, i + 1));

  const handleMouseMove = (e, idx) => {
    const rect = buttonRefs.current[idx]?.getBoundingClientRect();
    if (rect) {
      setMousePosition({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      });
    }
  };

  const handleMouseEnter = (idx) => {
    setIsHovering(true);
  };

  const handleMouseLeave = () => {
    setIsHovering(false);
  };

  return (
    <div className="w-full">
      <div className="hidden md:flex items-center gap-4 select-none">
        {items.map((item, idx) => (
          <button
            key={item.id}
            ref={(el) => (buttonRefs.current[idx] = el)}
            onClick={() => setActive(idx)}
            onMouseMove={(e) => handleMouseMove(e, idx)}
            onMouseEnter={() => handleMouseEnter(idx)}
            onMouseLeave={handleMouseLeave}
            className={cn(
              "flex-1 group p-3 rounded-lg transition-all relative overflow-hidden",
              idx !== items.length - 1 && "pr-4",
              active === idx 
                ? "bg-[#F4E9D7]" 
                : "bg-transparent hover:bg-beige-50"
            )}
            aria-current={active === idx}
          >
            {/* Efecto de gradiente que sigue al mouse */}
            {isHovering && (
              <div 
                className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                style={{
                  background: `radial-gradient(circle 80px at ${mousePosition.x}px ${mousePosition.y}px, rgba(7, 45, 66, 0.1) 0%, rgba(244, 233, 215, 0.2) 40%, transparent 60%)`
                }}
              />
            )}

            <div className="flex items-center gap-3 relative z-10">
              <div
                className={cn(
                  "size-8 shrink-0 rounded-full border grid place-items-center text-xs font-semibold transition-all",
                  active === idx
                    ? "border-transparent text-white bg-[#072D42] shadow-md group-hover:bg-gradient-to-r group-hover:from-[#072D42] group-hover:via-[#F4E9D7] group-hover:to-[#072D42] group-hover:bg-[length:200%_200%] group-hover:animate-gradient-x"
                    : "border-border bg-white text-brand-dark/80 group-hover:bg-gradient-to-r group-hover:from-[#072D42] group-hover:via-[#F4E9D7] group-hover:to-[#072D42] group-hover:bg-[length:200%_200%] group-hover:animate-gradient-x group-hover:text-white"
                )}
              >
                {idx + 1}
              </div>
              <div className="flex-1">
                <p className={cn("text-sm", active === idx ? "text-brand-dark font-medium" : "text-brand-dark/70")}>
                  {item.label}
                </p>
                <div
                  className={cn(
                    "h-1 rounded-full mt-1 transition-all",
                    active === idx
                      ? "bg-[#072D42] group-hover:bg-gradient-to-r group-hover:from-[#072D42] group-hover:via-[#F4E9D7] group-hover:to-[#072D42] group-hover:bg-[length:200%_200%] group-hover:animate-gradient-x"
                      : "bg-beige-300/60 group-hover:bg-gradient-to-r group-hover:from-[#072D42] group-hover:via-[#F4E9D7] group-hover:to-[#072D42] group-hover:bg-[length:200%_200%] group-hover:animate-gradient-x"
                  )}
                />
              </div>
            </div>
          </button>
        ))}
      </div>

      <div className="mt-6 rounded-xl p-[2px] bg-gradient-to-r from-[#072D42] via-[#F4E9D7] to-[#072D42] bg-[length:200%_200%] animate-gradient-x shadow-sm">
        <div className="bg-white rounded-xl p-6">
          <div className="flex items-center justify-between mb-4">
            <button
              onClick={prev}
              className="p-2 rounded-md border border-border hover:bg-beige-100 text-brand-dark"
              aria-label="Anterior"
            >
              <ChevronLeft className="size-5" />
            </button>
            <div className="text-center">
              <p className="text-xs uppercase tracking-wider text-brand-dark/60">
                {items[active].label}
              </p>
              <h4 className="font-serif text-2xl text-brand-dark mt-1">
                {items[active].title}
              </h4>
            </div>
            <button
              onClick={next}
              className="p-2 rounded-md border border-border hover:bg-beige-100 text-brand-dark"
              aria-label="Siguiente"
            >
              <ChevronRight className="size-5" />
            </button>
          </div>
          <p className="text-brand-dark/80 leading-relaxed">
            {items[active].description}
          </p>
        </div>
      </div>

      <div className="md:hidden mt-4 flex items-center justify-center gap-2 text-xs text-brand-dark/60">
        {items.map((_, i) => (
          <span
            key={i}
            className={cn(
              "h-1.5 w-6 rounded-full",
              i === active
                ? "bg-gradient-to-r from-[#072D42] via-[#F4E9D7] to-[#072D42]"
                : "bg-beige-300"
            )}
          />
        ))}
      </div>

      <style jsx>{`
        @keyframes gradient-x {
          0%, 100% { background-position: 0% 50%; }
          50% { background-position: 100% 50%; }
        }
        .animate-gradient-x {
          animation: gradient-x 3s ease infinite;
          background-size: 200% 200%;
        }
      `}</style>
    </div>
  );
}
